  pinned: { type: Boolean, default: false },
  badge: { type: String, default: '' },  // 自定义角标文字 (e.g. agent / org)
})
defineEmits(['click'])
</script>

<template>
  <div
    class="flex items-center gap-3 px-4 py-3 bg-white border-b border-akong-border/50 cursor-pointer active:bg-akong-paper transition-colors"
    @click="$emit('click')"
