    <div class="w-12 h-12 rounded-full overflow-hidden bg-akong-accent/10 border border-akong-accent/20 shrink-0">
      <img v-if="avatarSrc" :src="avatarSrc" class="w-full h-full" alt="" />
      <slot v-else name="avatar"></slot>
    </div>

    <div class="flex-1 min-w-0">
      <div class="flex items-center justify-between gap-2 mb-0.5">
        <div class="flex items-center gap-1.5 min-w-0">
          <span class="font-medium text-sm truncate" data-testid="conv-name">{{ name }}</span>
          <span
            v-if="pinned"
            class="text-[10px] px-1.5 py-0.5 rounded bg-akong-pin-bg text-akong-accent shrink-0"
            data-testid="pin-badge"
          >置顶</span>
          <span
            v-else-if="badge"
